from agent import *from models.products import *debug = Truedef process_revlist(data, context, session):   for rev in data.xpath("//h2[@class='entry-title']/a"):      url = rev.xpath("@href").string()      title = rev.xpath("descendant::text()").string(multiple=True)      if url and title:         session.queue(Request(url), process_review, dict(context, url=url, title=title))   nexturl = data.xpath("//a[@class='nextpostslink']/@href").string()   if nexturl:      session.queue(Request(nexturl), process_revlist, dict(context))def process_review(data, context, session):   product = Product()   product.name = data.xpath("//div[@id='titre-produit']/text()").string()   if not(product.name):      product.name = data.xpath("//span[@class='progress-bar-product']/text()").string()   if not(product.name):      product.name = data.xpath("//div[@id='titre-de-jeu']/text()").string()   if not(product.name):      product.name = context['title']   product.manufacturer = data.xpath("//div[@id='titre-produit']/span/text()").string()   product.url = context['url']   product.ssid = product.name   content = data.xpath("//div[@class='container-inner']//div[@class='pad group']").first()   if content:      product.category = data.xpath("descendant::li[@class='category']/a/text()").join('|')      review = Review()      review.type = 'pro'      review.title = context['title']      review.url = context['url']      review.ssid = re_search_once('post-(\d+)', content.xpath("article/@class").string())      product.reviews.append(review)      review.date = content.xpath("descendant::li[@class='date']//text()").string(multiple=True)      author = content.xpath(" descendant::li[@class='entry-author']/a").first()      if author:         url = author.xpath("@href").string()         name = author.xpath("descendant::text()").string(multiple=True)         if url and name:            review.authors.append(Person(name=name, profile_url=url, ssid=name))      summary = content.xpath(" descendant::div[@id='description']/text()").string(multiple=True)      if summary:         review.properties.append(ReviewProperty(type='summary', value=summary))      excerpt = content.xpath("div[@class='entry-part text']/p[normalize-space(text())][following-sibling::h2[regexp:test(normalize-space(.),'Conclusion')]]//text()").string(multiple=True)      if not(excerpt):         excerpt = content.xpath("div[@class='entry-part text']/p[normalize-space(text())][following-sibling::node()[regexp:test(normalize-space(.),'Conclusion')]]//text()").string(multiple=True)      if excerpt:         review.properties.append(ReviewProperty(type='excerpt', value=excerpt))      conclusion = content.xpath("div[@class='entry-part text']/p[normalize-space(text())][preceding-sibling::h2[regexp:test(normalize-space(.),'Conclusion')]]//text()").string(multiple=True)      if not(conclusion):         conclusion = content.xpath("div[@class='entry-part text']/p[normalize-space(text())][preceding-sibling::node()[regexp:test(normalize-space(.),'Conclusion')]]//text()").string(multiple=True)      if conclusion:         review.properties.append(ReviewProperty(type='conclusion', value=conclusion))      pros = content.xpath(" div[@class='entry-part text']//ul[@class='list plus']/li")      if not(pros):         pros = content.xpath(" div[@class='entry-part text']//p[regexp:test(normalize-space(.),'Points positifs')]/following-sibling::ul[1]/li")      for pro in pros:         line = pro.xpath("descendant::text()").string(multiple=True)         if line:            review.add_property(type='pros', value=line)      cons = content.xpath(" div[@class='entry-part text']//ul[@class='list minus']/li")      if not(cons):         cons = content.xpath(" div[@class='entry-part text']//p[regexp:test(normalize-space(.),'Points négatifs')]/following-sibling::ul[1]/li")      for con in cons:         line = con.xpath("descendant::text()").string(multiple=True)         if line:            review.add_property(type='cons', value=line)      ratetxt = content.xpath("descendant::button/text()").string(multiple=True)      if not(ratetxt):         ratetxt = content.xpath("descendant::span[@class='progressBar']/text()").string(multiple=True)      if not(ratetxt):         ratetxt = content.xpath("descendant::text()[regexp:test(normalize-space(.),'Note')]").string(multiple=True)      if ratetxt:         rate = re_search_once('(\d+)', ratetxt)         if rate and rate > 10:            review.grades.append(Grade(type='overall', name='Note de l’évaluation', value=float(rate), best=100.0))         elif rate:            review.grades.append(Grade(type='overall', name='Note de l’évaluation', value=float(rate), best=10.0))      for g in content.xpath("descendant::div[@class='progress-name']"):         title = g.xpath("descendant::text()").string(multiple=True)         value = g.xpath("following-sibling::div[@class='progress-score'][1]//text()").string(multiple=True)         if title and value:            review.grades.append(Grade(name=title, value=float(value), best=10.0))      for g in content.xpath("descendant::div[regexp:test(@class,'categorie')]"):         title = g.xpath("descendant::text()").string(multiple=True)         value = len(g.xpath(" following-sibling::div[1]/img[regexp:test(@src,'rating_on.png')]"))         if title and value:            review.grades.append(Grade(name=title, value=float(value), best=10.0))   if product.reviews:      session.emit(product)def run(context, session):   session.queue(Request('http://bloguedegeek.net/tag/evaluation/'), process_revlist, dict(category='unknown'))